var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"처마 아래 잘 차려 입은 남녀가 보이네.","JPN":"屋根の下、正装をした男女が見える。","ENG":"Under the eaves, a young couple stands dressed in their finest.","TWN":"我看到在屋簷下有一對穿著得體的男女。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"풋풋한 시절 함께 고운 정, 미운 정 다 들인 청춘 한 쌍일세.","JPN":"若き頃、酸いも甘いも共に味わいし一対の男女である。","ENG":"Two young souls who shared laughter, tears, and all the rough edges of youth.","TWN":"是一對處於青澀時光的歡喜冤家。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"상판에 올려진 나무 기러기도 한 쌍이지.","JPN":"卓上に置かれし木の雁も一対。","ENG":"Even the pair of wooden ducks on the table stand side by side.","TWN":"桌上擺飾的木製鴛鴦也是一對的。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"잔치를 벌이며 떠들썩하던 이들이 조용히 바라볼 동안…","JPN":"宴の喧騒も静まり、人々が黙々と見守る中……","ENG":"While the guests, so lively just moments ago, quiet down to watch…","TWN":"當這在宴會上喧鬧的人們安靜下來時…"},"stage":{"bg":"HANOK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"두 사람은 절을 올리고 잔을 나누며 고락을 함께 하기로 약속하니…","JPN":"2人は礼を交わし、杯を交え、苦楽を共にすることを誓い……","ENG":"The couple bows, shares a drink, vowing to walk through all trials together…","TWN":"兩人互相行禮，喝下交杯酒，承諾將來同甘共苦…"},"stage":{"bg":"HANOK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그 시절의 방식을 모르는 눈으로 보아도 백년가약을 청하는 자리임을 알겠더군.","JPN":"当時の作法を知らぬ某の目にも、それが百年の契りを交わす席であると分かった。","ENG":"Even to eyes unfamiliar with old customs, it's clear they are tying the knot.","TWN":"即使不清楚那個時代的習俗，也看得出來這是一個互訂終身的場合。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"허나 다분히 반짝이던 행복도 잠시…","JPN":"されど、きらめく幸せもつかの間……","ENG":"Yet that bright, fleeting happiness fades so quickly…","TWN":"然而，那閃耀的幸福也是稍縱即逝…"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"햇빛이 검은 구름에 가려지고 모인 사람들은 사방팔방으로 도망치기 시작하네.","JPN":"陽の光は黒雲に遮られ、集いし人々は四方八方へと逃げ出し始める。","ENG":"The sunlight gives way to dark clouds, and panic drives the guests to scatter.","TWN":"陽光被烏雲遮蔽，聚集的人們開始四處逃竄。"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"공포에 질린 눈을 굴리며, 검은 비를 맞으며, 무어라도 붙잡을 기세로 절박하게 외쳐대지.","JPN":"恐怖に慄く目で周囲を見回し、黒き雨に打たれながら、何かにすがるように必死に叫び続ける。","ENG":"Eyes wide with terror, they shout desperately for anything to hold onto, drenched in black rain.","TWN":"他們眼中充滿恐懼，淋著墨雨，絕望地大喊，彷彿想抓住一線生機。"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"범이다.","JPN":"虎だ。","ENG":"A tiger.","TWN":"老虎。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"범이 나타났다.","JPN":"虎が現れた。","ENG":"A tiger has come.","TWN":"是老虎。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"녹아내리는 이성을 부여잡고 통곡하며, 한때 웃고 떠들던 이들의 이빨에 찢겨 발겨져.","JPN":"溶け落ちゆく理性を繋ぎ止めて慟哭し、つい先程まで共に笑い騒いでいた者たちの歯によって引き裂かれ。","ENG":"Sanity dissolves as the laughing crowd rips and tears at each other with jagged teeth.","TWN":"他們用僅存的理智放聲痛哭，被曾經歡笑的人們用牙齒撕裂。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_BLOOD_SPREAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"웃기 위해 모인 자리엔 살점과 피가 범벅이 되어 비린 비명만 바람을 타고 바삐 떠돌아.","JPN":"祝宴の場には肉片と血が混ざり合い、生臭い悲鳴のみが風に乗りこだまする。","ENG":"A gathering meant for smiles now soaked with flesh and blood. Only raw screams riding the wind.","TWN":"原本歡樂的場合，只剩下血肉模糊，以及此起彼落的哀號聲。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_BLOOD_SPREAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"그 아수라장 한복판엔 여인이 주저앉아 피눈물을 흘리네.","JPN":"その修羅場の真ん中で女性が崩れ落ち、血の涙を流している。","ENG":"In the chaos, a woman kneels, tears of blood streaming down her face.","TWN":"在那悽慘的景象中，一個女人跪在地上流著血淚。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"백년가약을 약속했던 사내의 가슴에 자기 발톱을 박은 괴물이 되어…","JPN":"怪物と化した己の爪を、百年の契りを交わした男の胸に突き立てて……","ENG":"She became a monster who drove her claws into the chest of the man she once vowed a lifelong bond with…","TWN":"她變成怪物，將自己的爪子插進那曾經與她互許終身的男人胸膛…"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"그 비극이 오랫동안 되풀이되던 내 악몽 중 하나였음을 깨달을 때 즈음이면…","JPN":"その悲劇が、長らく繰り返されてきた悪夢の1つであると悟る頃……","ENG":"Just as I realize this nightmare is one I've relived countless times…","TWN":"當我意識到，這個悲劇是我長久以來反覆做的惡夢之一時…"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"여인은 문득 고개 들어 하늘을 보며 읊조렸다네.","JPN":"女性は不意に顔を上げ、空を仰ぎ、失笑まじりに呟やくのであった。","ENG":"She lifts her head to the sky, laughing bitterly.","TWN":"女人突然抬頭看著天空，輕聲說道。"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"거 보세요, 서방님.","JPN":"「ほら見てください、あなた。」","ENG":"\\"Look, my love.\\"","TWN":"你看吧，夫君。"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"또 이렇게 되고 말았잖아요.","JPN":"「またもやこのような結末になってしまったではありませんか。」","ENG":"\\"It's happened all over again.\\"","TWN":"又變得如此這般。"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"아, 깨어났다.","JPN":"あ、起きた。","ENG":"Ah, you're awake.","TWN":"喔，你醒來啦。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"}}}}]`);export{e as default};